test "buildIsupportTokens replaces length tokens with configured values" {
    const tokens = try buildIsupportTokens(std.testing.allocator, .{ .port = 0, .topiclen = 512, .awaylen = 200, .kicklen = 100, .nicklen = 30, .channellen = 50, .maxlist = 25, .chanlimit = 12, .maxtargets = 3, .monitorlimit = 64, .silencelimit = 16 });
    defer freeIsupportTokens(std.testing.allocator, tokens);

    var hits: usize = 0;
    for (tokens) |tok| {
        if (std.mem.eql(u8, tok, "TOPICLEN=512")) hits += 1;
        if (std.mem.eql(u8, tok, "AWAYLEN=200")) hits += 1;
        if (std.mem.eql(u8, tok, "KICKLEN=100")) hits += 1;
        if (std.mem.eql(u8, tok, "NICKLEN=30")) hits += 1;
        if (std.mem.eql(u8, tok, "CHANNELLEN=50")) hits += 1;
        if (std.mem.eql(u8, tok, "MAXLIST=beIZ:25")) hits += 1;
        if (std.mem.eql(u8, tok, "CHANLIMIT=#&:12")) hits += 1;
        if (std.mem.eql(u8, tok, "MAXTARGETS=3")) hits += 1;
        if (std.mem.eql(u8, tok, "MONITOR=64")) hits += 1;
        if (std.mem.eql(u8, tok, "SILENCE=16")) hits += 1;
        // static tokens carry through unchanged.
        if (std.mem.startsWith(u8, tok, "NETWORK=")) try std.testing.expect(tok.len > "NETWORK=".len);
    }
    try std.testing.expectEqual(@as(usize, 10), hits);
    // base tokens + the two derived ones (PREFIX, STATUSMSG) appended from chanmode.
    try std.testing.expectEqual(protocol_inventory.isupport_tokens.len + 2, tokens.len);
    // PREFIX/STATUSMSG come from the single source of truth, not a hardcoded copy.
    var saw_prefix = false;
    var saw_statusmsg = false;
    for (tokens) |tok| {
        if (std.mem.eql(u8, tok, "PREFIX=" ++ chanmode.MemberModes.isupport_prefix)) saw_prefix = true;
        if (std.mem.eql(u8, tok, "STATUSMSG=" ++ chanmode.MemberModes.statusmsg_symbols)) saw_statusmsg = true;
    }
    try std.testing.expect(saw_prefix and saw_statusmsg);
}

test "buildIsupportTokens advertises NETWORKICON only when configured" {
    // No icon configured: NETWORKICON absent, count stays base + 2.
    const plain = try buildIsupportTokens(std.testing.allocator, .{ .port = 0 });
    defer freeIsupportTokens(std.testing.allocator, plain);
    for (plain) |tok| try std.testing.expect(!std.mem.startsWith(u8, tok, "NETWORKICON="));
    try std.testing.expectEqual(protocol_inventory.isupport_tokens.len + 2, plain.len);

    // Icon configured: NETWORKICON=<url> present, count is base + 3.
    const with_icon = try buildIsupportTokens(
        std.testing.allocator,
        .{ .port = 0, .network_icon_url = "https://eshmaki.me/icon.png" },
    );
    defer freeIsupportTokens(std.testing.allocator, with_icon);
    var saw = false;
    for (with_icon) |tok| {
        if (std.mem.eql(u8, tok, "NETWORKICON=https://eshmaki.me/icon.png")) saw = true;
    }
    try std.testing.expect(saw);
    try std.testing.expectEqual(protocol_inventory.isupport_tokens.len + 3, with_icon.len);
}

test "utf8TruncateBytes caps length without splitting a codepoint" {
    // ASCII: exact byte cut.
    try std.testing.expectEqualStrings("hello", LinuxServer.utf8TruncateBytes("hello world", 5));
    // Short input passes through unchanged.
    try std.testing.expectEqualStrings("hi", LinuxServer.utf8TruncateBytes("hi", 10));
    // "é" is 0xC3 0xA9; cutting mid-sequence backs off to the codepoint start.
    const s = "a\u{00e9}b"; // a, é (2 bytes), b -> 4 bytes total
    try std.testing.expectEqualStrings("a", LinuxServer.utf8TruncateBytes(s, 2));
    try std.testing.expectEqualStrings("a\u{00e9}", LinuxServer.utf8TruncateBytes(s, 3));
}

