    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }
    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try recvUntil(&b, " 001 B ", 200);
    try writeAllFd(fd_a, "IRCX\r\n");
    try writeAllFd(fd_b, "IRCX\r\n");
    try recvUntil(&a, " 800 A 1 0 ", 200);
    try recvUntil(&b, " 800 B 1 0 ", 200);
    // Serialize the joins so A is deterministically the first member (and thus
    // channel-op) before B joins — with the sharded reactor pool, writing both
    // JOINs before reading either 366 races on who becomes op.
    try writeAllFd(fd_a, "JOIN #dm\r\n");
    try recvUntil(&a, " 366 A #dm ", 200);
    try writeAllFd(fd_b, "JOIN #dm\r\n");
    try recvUntil(&b, " 366 B #dm ", 200);
    a.reset();
    try writeAllFd(fd_a, "MODE #dm +m\r\n");
    try recvUntil(&a, "MODE #dm +m", 200);

    b.reset();
    try writeAllFd(fd_b, "DATA #dm TAG :blocked\r\n");
    try recvUntil(&b, " 404 B #dm :Cannot send to channel (+m)", 200);
}

test "threaded server: +V NOCOMICDATA refuses non-op DATA with 531" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    // A founds #v, opts into IRCX, and sets +V (NOCOMICDATA). Serialized so the
    // mode is committed before B joins/sends.
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try writeAllFd(fd_a, "IRCX\r\n");
    try recvUntil(&a, " 800 A 1 0 ", 200);
    try writeAllFd(fd_a, "JOIN #v\r\n");
    try recvUntil(&a, " 366 A #v ", 200);
    try writeAllFd(fd_a, "MODE #v +V\r\n");
    try recvUntil(&a, "MODE #v +V", 200);

    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&b, " 001 B ", 200);
    try writeAllFd(fd_b, "IRCX\r\n");
    try recvUntil(&b, " 800 B 1 0 ", 200);
    try writeAllFd(fd_b, "JOIN #v\r\n");
    try recvUntil(&b, " 366 B #v ", 200);

    // B (a plain member) is refused DATA with ERR_NOCOMICDATA (531).
    b.reset();
    try writeAllFd(fd_b, "DATA #v TAG :blocked\r\n");
    try recvUntil(&b, " 531 B #v :", 200);

    // A (founder/channel-op) bypasses +V: its DATA reaches B.
    b.reset();
    try writeAllFd(fd_a, "DATA #v TAG :fromop\r\n");
    try recvUntil(&b, "DATA #v TAG :fromop", 200);
}

test "threaded server: +U OPMODERATE routes a muted member's message to ops only" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    const fd_c = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_c);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };
    var c = LiveClient{ .fd = fd_c };

    // A founds #o (founder/op) and makes it +m (moderated) + +U (opmoderate);
    // B and C join as plain, non-voiced members. Serialized so the modes commit
    // before anyone speaks.
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try writeAllFd(fd_a, "JOIN #o\r\n");
    try recvUntil(&a, " 366 A #o ", 200);
    try writeAllFd(fd_a, "MODE #o +m\r\n");
    try recvUntil(&a, "MODE #o +m", 200);
    try writeAllFd(fd_a, "MODE #o +U\r\n");
    try recvUntil(&a, "MODE #o +U", 200);

    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&b, " 001 B ", 200);
    try writeAllFd(fd_b, "JOIN #o\r\n");
    try recvUntil(&b, " 366 B #o ", 200);
    try writeAllFd(fd_c, "NICK C\r\nUSER carol 0 * :Carol\r\n");
    try recvUntil(&c, " 001 C ", 200);
    try writeAllFd(fd_c, "JOIN #o\r\n");
    try recvUntil(&c, " 366 C #o ", 200);

    // B (muted under +m) speaks: instead of a 404, the message is routed to ops
    // only — A (op) receives it, with no error back to B.
    a.reset();
    c.reset();
    try writeAllFd(fd_b, "PRIVMSG #o :muted-attempt\r\n");
    try recvUntil(&a, "PRIVMSG #o :muted-attempt", 200);

    // A (op, may speak) sends a normal message that reaches every member. C
    // receiving THIS but never the earlier routed-to-ops line proves the muted
    // attempt was withheld from non-ops (deterministic ordering, no flaky sleep).
    try writeAllFd(fd_a, "PRIVMSG #o :op-says-hi\r\n");
    try recvUntil(&c, "PRIVMSG #o :op-says-hi", 200);
    try std.testing.expect(std.mem.indexOf(u8, c.written(), "muted-attempt") == null);
}

test "threaded server: +U OPMODERATE held message surfaces a POLICY event to opers" {
    // operTestConfig defaults to one shard, so the muted member and the oper
    // share a reactor (publishOperEvent reaches same-reactor subscribers — a
    // pre-existing limitation under num_shards>1, out of scope here).
    var server = Server.init(std.testing.allocator, operTestConfig(0)) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    // A is a network oper (auto-subscribed to POLICY on SASL elevation) and the
    // founder/op of #o, which it makes +m (moderated) + +U (opmoderate).
    try saslAdminPrelude(fd_a);
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try recvUntil(&a, " 381 A ", 200);
    try writeAllFd(fd_a, "JOIN #o\r\n");
    try recvUntil(&a, " 366 A #o ", 200);
    try writeAllFd(fd_a, "MODE #o +m\r\n");
    try recvUntil(&a, "MODE #o +m", 200);
    try writeAllFd(fd_a, "MODE #o +U\r\n");
    try recvUntil(&a, "MODE #o +U", 200);

    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&b, " 001 B ", 200);
    try writeAllFd(fd_b, "JOIN #o\r\n");
    try recvUntil(&b, " 366 B #o ", 200);

    // B (muted) speaks: besides the raw routed copy, A receives a structured
    // POLICY event naming the channel, sender, and held text.
    a.reset();
    try writeAllFd(fd_b, "PRIVMSG #o :held-here\r\n");
    try recvUntil(&a, "NOTE EVENT POLICY :#o held message from B: held-here", 200);
}

test "threaded server: DATA STATUSMSG target reaches ops only" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }
    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    const fd_c = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_c);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };
    var c = LiveClient{ .fd = fd_c };
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try writeAllFd(fd_c, "NICK C\r\nUSER carol 0 * :Carol\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try recvUntil(&b, " 001 B ", 200);
    try recvUntil(&c, " 001 C ", 200);
    try writeAllFd(fd_a, "IRCX\r\n");
    try writeAllFd(fd_b, "IRCX\r\n");
    try writeAllFd(fd_c, "IRCX\r\n");
    try recvUntil(&a, " 800 A 1 0 ", 200);
    try recvUntil(&b, " 800 B 1 0 ", 200);
    try recvUntil(&c, " 800 C 1 0 ", 200);
    // Serialize the joins so A is deterministically first (channel-op) before
    // B/C join — the sharded reactor pool otherwise races on who becomes op.
    try writeAllFd(fd_a, "JOIN #ds\r\n");
    try recvUntil(&a, " 366 A #ds ", 200);
    try writeAllFd(fd_b, "JOIN #ds\r\n");
    try recvUntil(&b, " 366 B #ds ", 200);
    try writeAllFd(fd_c, "JOIN #ds\r\n");
    try recvUntil(&c, " 366 C #ds ", 200);
    try writeAllFd(fd_a, "MODE #ds +o B\r\n");
    try recvUntil(&b, "MODE #ds +o B", 200);

    b.reset();
    c.reset();
    try writeAllFd(fd_a, "DATA @#ds TAG :ops\r\n");
    try recvUntil(&b, ":A!alice@localhost DATA @#ds TAG :ops\r\n", 200);
    try c.readAvailable();
    try std.testing.expect(std.mem.indexOf(u8, c.written(), "DATA @#ds TAG :ops") == null);

    c.reset();
    try writeAllFd(fd_c, "DATA @#ds TAG :sneaky\r\n");
    try recvUntil(&c, " 482 C @#ds ", 200);
}

test "threaded server: LISTX filters on real channel SUBJECT from the PROP store" {
    // Proves the LISTX handler reads real channel data (not hardcoded blanks):
    // the S= subject filter must match a channel whose SUBJECT prop was set and
    // exclude one with no subject.
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }
    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const alloc = std.testing.allocator;
    const a = try alloc.create(LiveClient);
    defer alloc.destroy(a);
    a.* = .{ .fd = fd_a };
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try recvUntil(a, " 001 A ", 200);
    try writeAllFd(fd_a, "IRCX\r\n");
    try recvUntil(a, " 800 A 1 0 ", 200);
    try writeAllFd(fd_a, "JOIN #alpha\r\n");
    try recvUntil(a, " 366 A #alpha ", 200);
    try writeAllFd(fd_a, "JOIN #beta\r\n");
    try recvUntil(a, " 366 A #beta ", 200);
    a.reset();
    try writeAllFd(fd_a, "PROP #alpha SUBJECT :ziglang\r\n");
    try recvUntil(a, " 818 A #alpha ", 200);

    // S=zig* matches #alpha's real subject and excludes #beta (no subject).
    a.reset();
    try writeAllFd(fd_a, "LISTX S=zig*\r\n");
    try recvUntil(a, " 817 ", 200); // RPL_LISTXEND
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "#alpha") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "#beta") == null);
}

test "threaded server: LISTX emits PICS 813 after channel entries" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();

    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    var a = LiveClient{ .fd = fd_a };

    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try writeAllFd(fd_a, "IRCX\r\n");
    try recvUntil(&a, " 800 A 1 0 ", 200);
    try writeAllFd(fd_a, "JOIN #alpha\r\n");
    try recvUntil(&a, " 366 A #alpha ", 200);
    // Seed PICS AFTER the creating JOIN: channel creation clearChannel-purges any
    // pre-seeded IRCX state, so seeding before would be wiped before LISTX.
    _ = try server.props.setProp(
        try ircx_prop_store.Entity.fromId("#alpha"),
        "PICS",
        "rated-safe",
        .{ .id = "server", .access = .server },
    );
    try writeAllFd(fd_a, "JOIN #beta\r\n");
    try recvUntil(&a, " 366 A #beta ", 200);

    a.reset();
    try writeAllFd(fd_a, "LISTX\r\n");
    try recvUntil(&a, " 817 ", 200);

    const written = a.written();
    const entry_index = std.mem.indexOf(u8, written, " 812 A #alpha ") orelse return error.TestExpectedEqual;
    const pics_index = std.mem.indexOf(u8, written, " 813 A #alpha :rated-safe\r\n") orelse return error.TestExpectedEqual;
    try std.testing.expect(pics_index > entry_index);
    try std.testing.expect(std.mem.indexOf(u8, written, " 813 A #beta ") == null);
}

test "threaded server: PROP set/get gated by channel-op" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }
    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    const alloc = std.testing.allocator;
    const a = try alloc.create(LiveClient);
    defer alloc.destroy(a);
    const b = try alloc.create(LiveClient);
    defer alloc.destroy(b);
    a.* = .{ .fd = fd_a };
    b.* = .{ .fd = fd_b };
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(a, " 001 A ", 200);
    try recvUntil(b, " 001 B ", 200);
    try writeAllFd(fd_a, "IRCX\r\n");
    try writeAllFd(fd_b, "IRCX\r\n");
    try recvUntil(a, " 800 A 1 0 ", 200);
    try recvUntil(b, " 800 B 1 0 ", 200);
    try writeAllFd(fd_a, "JOIN #p\r\n");
    try recvUntil(a, " 366 A #p ", 200);
    // Founder A sets a channel property and reads it back (818 + 819).
    a.reset();
    try writeAllFd(fd_a, "PROP #p SUBJECT :hello\r\n");
    try recvUntil(a, " 818 A #p ", 200);
    try recvUntil(a, " 819 A #p ", 200);
    a.reset();
    try writeAllFd(fd_a, "PROP #p SUBJECT\r\n");
    try recvUntil(a, " 818 A #p ", 200);
    // B, not on the channel, cannot set channel props (ERR_NOACCESS 913).
    b.reset();
    try writeAllFd(fd_b, "PROP #p SUBJECT :nope\r\n");
    try recvUntil(b, " 913 ", 200);
    // A sets a SECRET key; B (no write access) must not be able to read it back —
    // the GET returns only the 819 end with no 818/value leak.
    a.reset();
    try writeAllFd(fd_a, "PROP #p OWNERKEY :sekret\r\n");
    try recvUntil(a, " 818 A #p ", 200);
    b.reset();
    try writeAllFd(fd_b, "PROP #p OWNERKEY\r\n");
    try recvUntil(b, " 819 B #p ", 200);
    try std.testing.expect(std.mem.indexOf(u8, b.written(), "sekret") == null);
    try std.testing.expect(std.mem.indexOf(u8, b.written(), " 818 ") == null);

    // Verb forms: SET writes, GET can read computed built-ins, CLEAR removes
    // stored props while preserving client-safe replies.
    a.reset();
    try writeAllFd(fd_a, "PROP #p SET TOPIC :verb\r\n");
    try recvUntil(a, " 818 A #p TOPIC :verb", 200);
    try recvUntil(a, " 819 A #p ", 200);
    a.reset();
    try writeAllFd(fd_a, "PROP #p GET NAME\r\n");
    try recvUntil(a, " 818 A #p NAME :#p", 200);
    try recvUntil(a, " 819 A #p ", 200);
    a.reset();
    try writeAllFd(fd_a, "PROP #p CLEAR\r\n");
    try recvUntil(a, " 819 A #p ", 200);
    a.reset();
    try writeAllFd(fd_a, "PROP #p GET TOPIC\r\n");
    try recvUntil(a, " 819 A #p ", 200);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "verb") == null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), " 818 ") == null);
}

test "threaded server: PROP user profile extended keys round-trip and enforce access" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try recvUntil(&b, " 001 B ", 200);
    try writeAllFd(fd_a, "IRCX\r\n");
    try writeAllFd(fd_b, "IRCX\r\n");
    try recvUntil(&a, " 800 A 1 0 ", 200);
    try recvUntil(&b, " 800 B 1 0 ", 200);

    const cases = [_]struct {
        key: []const u8,
        value: []const u8,
        profile_fragment: []const u8,
    }{
        .{ .key = "URL", .value = "https://example.test/a", .profile_fragment = "url=https://example.test/a" },
        .{ .key = "GENDER", .value = "nonbinary", .profile_fragment = "gender=nonbinary" },
        .{ .key = "PICTURE", .value = "https://example.test/a.png", .profile_fragment = "picture=https://example.test/a.png" },
        .{ .key = "BIO", .value = "Orochi operator", .profile_fragment = "bio=Orochi operator" },
        .{ .key = "EMAIL", .value = "alice@example.test", .profile_fragment = "email=alice@example.test" },
    };

    for (cases) |case| {
        a.reset();
        try writeAllFd(fd_a, "PROP A SET ");
        try writeAllFd(fd_a, case.key);
        try writeAllFd(fd_a, " :");
        try writeAllFd(fd_a, case.value);
        try writeAllFd(fd_a, "\r\n");
        try recvUntil(&a, " 819 A A ", 200);
        try std.testing.expect(std.mem.indexOf(u8, a.written(), case.value) != null);

        a.reset();
        try writeAllFd(fd_a, "PROP A GET ");
        try writeAllFd(fd_a, case.key);
        try writeAllFd(fd_a, "\r\n");
        try recvUntil(&a, " 819 A A ", 200);
        try std.testing.expect(std.mem.indexOf(u8, a.written(), case.value) != null);
    }

    a.reset();
    try writeAllFd(fd_a, "PROP A GET user_profile\r\n");
    try recvUntil(&a, " 818 A A user_profile :", 200);
    try recvUntil(&a, " 819 A A ", 200);
    for (cases) |case| {
        try std.testing.expect(std.mem.indexOf(u8, a.written(), case.profile_fragment) != null);
    }

    var too_long = [_]u8{'x'} ** (ircx_prop_store.user_profile_max_value + 1);
    a.reset();
    try writeAllFd(fd_a, "PROP A SET URL :");
    try writeAllFd(fd_a, too_long[0..]);
    try writeAllFd(fd_a, "\r\n");
    try recvUntil(&a, " 913 ", 200);

    b.reset();
    try writeAllFd(fd_b, "PROP A SET URL :https://example.test/b\r\n");
    try recvUntil(&b, " 913 ", 200);

    b.reset();
    try writeAllFd(fd_b, "PROP A SET display :Mallory\r\n");
    try recvUntil(&b, " 913 ", 200);
}

test "threaded server: PROP user MEMBER_OF lists visible channels (WHOIS filter)" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
