test "threaded server: +g callerid gates DM until sender is accepted" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    // Two distinct clients: A (sender), B (recipient). Neither is an oper or
    // shares an account, so the +g gate is the only thing that can block A.
    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&b, " 001 B ", 200);

    // B enables caller-id (+g): only accepted senders may DM it.
    try writeAllFd(fd_b, "MODE B +g\r\n");
    try recvUntil(&b, "MODE B +g", 200);

    // A (not on B's accept list) DMs B → A gets 716, B gets 718, and the DM
    // body never reaches B.
    a.reset();
    b.reset();
    try writeAllFd(fd_a, "PRIVMSG B :blocked-by-callerid\r\n");
    try recvUntil(&a, " 716 A B :is in +g mode", 200);
    // 718 carries the sender's nick + user@host as distinct tokens (host
    // rendering of loopback varies, so assert the user@ prefix, not the host).
    try recvUntil(&b, " 718 B A alice@", 200);
    try std.testing.expect(std.mem.indexOf(u8, b.written(), "blocked-by-callerid") == null);

    // B accepts A; confirm the add landed (ACCEPT list shows A) before resending
    // so the PRIVMSG cannot race ahead of the accept-list mutation.
    b.reset();
    try writeAllFd(fd_b, "ACCEPT +A\r\nACCEPT\r\n");
    try recvUntil(&b, " 281 B A", 200);
    try recvUntil(&b, " 282 B ", 200);

    b.reset();
    try writeAllFd(fd_a, "PRIVMSG B :now-delivered\r\n");
    try recvUntil(&b, "PRIVMSG B :now-delivered", 200);
}

test "threaded server: METADATA set then get" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }
    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    var a = LiveClient{ .fd = fd_a };
    try writeAllFd(fd_a, "CAP REQ :draft/metadata-2\r\nNICK A\r\nUSER alice 0 * :Alice\r\nCAP END\r\n");
    try recvUntil(&a, " 001 A ", 200);
    a.reset();
    try writeAllFd(fd_a, "METADATA * SET url members :http://x\r\n");
    try recvUntil(&a, " 761 A * url members :http://x", 200);
    try recvUntil(&a, " 762 A ", 200);
    a.reset();
    try writeAllFd(fd_a, "METADATA * GET url\r\n");
    try recvUntil(&a, " 761 A * url members :http://x", 200);
    // Writing another user's metadata is denied (ERR_KEYNOPERMISSION 769).
    a.reset();
    try writeAllFd(fd_a, "METADATA Bob SET url :http://j\r\n");
    try recvUntil(&a, " 769 A Bob url ", 200);
    // A second client's `*` namespace is isolated from A's: B's GET misses (766),
    // proving `*` resolves per-client rather than into one shared bucket.
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var b = LiveClient{ .fd = fd_b };
    try writeAllFd(fd_b, "CAP REQ :draft/metadata-2\r\nNICK B\r\nUSER bob 0 * :Bob\r\nCAP END\r\n");
    try recvUntil(&b, " 001 B ", 200);
    b.reset();
    try writeAllFd(fd_b, "METADATA * GET url\r\n");
    try recvUntil(&b, " 766 B * url ", 200);
}

