test "threaded server: draft/event-playback replays TOPIC events only to capable clients" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }
    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    // A negotiates chathistory + event-playback; B only chathistory.
    try writeAllFd(fd_a, "CAP REQ :draft/chathistory draft/event-playback batch\r\nNICK A\r\nUSER alice 0 * :Alice\r\nCAP END\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try writeAllFd(fd_b, "CAP REQ :draft/chathistory batch\r\nNICK B\r\nUSER bob 0 * :Bob\r\nCAP END\r\n");
    try recvUntil(&b, " 001 B ", 200);
    // A founds #ep (so it may set the topic); B joins.
    try writeAllFd(fd_a, "JOIN #ep\r\n");
    try recvUntil(&a, " 366 A #ep ", 200);
    try writeAllFd(fd_b, "JOIN #ep\r\n");
    try recvUntil(&b, " 366 B #ep ", 200);

    // A message (recorded as PRIVMSG) and a topic change (recorded as a TOPIC event).
    a.reset();
    try writeAllFd(fd_b, "PRIVMSG #ep :hello-there\r\n");
    try recvUntil(&a, "PRIVMSG #ep :hello-there", 200);
    try writeAllFd(fd_a, "TOPIC #ep :the-topic\r\n");
    try recvUntil(&a, "TOPIC #ep :the-topic", 200);

    // A (event-playback) replays BOTH the message and the TOPIC event.
    a.reset();
    try writeAllFd(fd_a, "CHATHISTORY LATEST #ep * 10\r\n");
    try recvUntil(&a, "BATCH +1 chathistory #ep", 200);
    try recvUntil(&a, "PRIVMSG #ep :hello-there", 200);
    try recvUntil(&a, "TOPIC #ep :the-topic", 200);
    try recvUntil(&a, "BATCH -1", 200);

    // Drain B's LIVE copy of the topic (B is a member; it has no echo-message so
    // it never saw its own PRIVMSG) before the negative assertion, so it inspects
    // only the replayed batch and not the pending live broadcast in B's socket.
    try recvUntil(&b, "TOPIC #ep :the-topic", 200);

    // B (no event-playback) replays the message only — the TOPIC event is filtered.
    b.reset();
    try writeAllFd(fd_b, "CHATHISTORY LATEST #ep * 10\r\n");
    try recvUntil(&b, "BATCH +1 chathistory #ep", 200);
    try recvUntil(&b, "PRIVMSG #ep :hello-there", 200);
    try recvUntil(&b, "BATCH -1", 200);
    try std.testing.expect(std.mem.indexOf(u8, b.written(), "TOPIC #ep :the-topic") == null);

    // A second event type: B parts with a reason (a PART event). A (event-playback)
    // replays it verbatim via the generalized event renderer (`:sender CMD body`).
    a.reset();
    try writeAllFd(fd_b, "PART #ep :goodbye-all\r\n");
    try recvUntil(&a, "PART #ep :goodbye-all", 200);
    a.reset();
    try writeAllFd(fd_a, "CHATHISTORY LATEST #ep * 10\r\n");
    try recvUntil(&a, ":B!bob@localhost PART #ep :goodbye-all", 200);
    try recvUntil(&a, "BATCH -1", 200);
}

test "threaded server: event-playback replays JOIN, MODE, and KICK events" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }
    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    // A (event-playback) founds #jk; B joins (a JOIN event); A kicks B (a KICK event).
    try writeAllFd(fd_a, "CAP REQ :draft/chathistory draft/event-playback batch\r\nNICK A\r\nUSER alice 0 * :Alice\r\nCAP END\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&b, " 001 B ", 200);
    try writeAllFd(fd_a, "JOIN #jk\r\n");
    try recvUntil(&a, " 366 A #jk ", 200);
    try writeAllFd(fd_b, "JOIN #jk\r\n");
    try recvUntil(&b, " 366 B #jk ", 200);
    a.reset();
    try writeAllFd(fd_a, "MODE #jk +m\r\n");
    try recvUntil(&a, "MODE #jk +m", 200);
    try writeAllFd(fd_a, "KICK #jk B :rude\r\n");
    try recvUntil(&a, "KICK #jk B :rude", 200);

    // A replays: JOIN (no-trailing body), MODE (modestring body), and KICK
    // (multi-param body) events all render verbatim through the generalized
    // event renderer, oldest-first.
    a.reset();
    try writeAllFd(fd_a, "CHATHISTORY LATEST #jk * 10\r\n");
    try recvUntil(&a, "BATCH +1 chathistory #jk", 200);
    try recvUntil(&a, ":B!bob@localhost JOIN #jk", 200);
    try recvUntil(&a, ":A!alice@localhost MODE #jk +m", 200);
    try recvUntil(&a, ":A!alice@localhost KICK #jk B :rude", 200);
    try recvUntil(&a, "BATCH -1", 200);
}

test "threaded server: event-playback replays NICK and QUIT events" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }
    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    // A (event-playback) founds #nq; B joins, renames, then quits — both are
    // cross-channel events recorded into #nq's history.
    try writeAllFd(fd_a, "CAP REQ :draft/chathistory draft/event-playback batch\r\nNICK A\r\nUSER alice 0 * :Alice\r\nCAP END\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&b, " 001 B ", 200);
    try writeAllFd(fd_a, "JOIN #nq\r\n");
    try recvUntil(&a, " 366 A #nq ", 200);
    try writeAllFd(fd_b, "JOIN #nq\r\n");
    try recvUntil(&b, " 366 B #nq ", 200);

    a.reset();
    try writeAllFd(fd_b, "NICK Bob2\r\n");
    try recvUntil(&a, ":B!bob@localhost NICK :Bob2", 200);
    try writeAllFd(fd_b, "QUIT :bye-now\r\n");
    try recvUntil(&a, ":Bob2!bob@localhost QUIT :bye-now", 200);

    // A replays both the NICK (old prefix) and QUIT (renamed prefix) events,
    // matching the live broadcast format.
    a.reset();
    try writeAllFd(fd_a, "CHATHISTORY LATEST #nq * 10\r\n");
    try recvUntil(&a, "BATCH +1 chathistory #nq", 200);
    try recvUntil(&a, ":B!bob@localhost NICK :Bob2", 200);
    try recvUntil(&a, ":Bob2!bob@localhost QUIT :bye-now", 200);
    try recvUntil(&a, "BATCH -1", 200);
}

test "threaded server: CHATHISTORY DM history follows accounts over reused nicks" {
    var server = Server.init(std.testing.allocator, multiOperTestConfig(0)) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
